+import type { DeferredCommand, DeferredScope, DeferredWorld, World } from './types';
+
+function commands(world: World) {
+    return world[$internal].deferredScopes.flatMap((scope) => scope.commands);
+}
+
+function entityState(world: World, entity: Entity): boolean {
+    let alive = isEntityAlive(world[$internal].entityIndex, entity);
+    for (const command of commands(world)) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'spawn') alive = true;
+        else if (command.type === 'destroy') alive = false;
+    }
+    return alive;
+}
+
+/** The deferred view is deliberately small: it is used by entity.has/get while a loop is running. */
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): boolean {
+    if (!entityState(world, entity)) return false;
+    let value = isEntityAlive(world[$internal].entityIndex, entity)
+        ? isRelationPair(trait)
+            ? hasRelationPair(world, entity, trait)
+            : hasTrait(world, entity, trait)
+        : false;
+    for (const command of commands(world)) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') return false;
+        if (command.type === 'remove') {
+            for (const removed of command.traits) {
+                if (removed === trait) value = false;
+                if (isRelationPair(removed) && isRelationPair(trait)) {
+                    const a = removed[$internal], b = trait[$internal];
+                    if (a.relation === b.relation && (a.target === '*' || a.target === b.target)) value = false;
+                }
+            }
+        }
+        if (command.type === 'add' || command.type === 'spawn' || command.type === 'addExclusive') {
+            for (const added of command.traits) {
+                const base = Array.isArray(added) ? added[0] : added;
+                if (base === trait) value = true;
+                if (isRelationPair(base) && isRelationPair(trait)) {
+                    const a = base[$internal], b = trait[$internal];
+                    if (a.relation === b.relation) {
+                        if (command.type === 'addExclusive' && a.target === '*') value = false;
+                        else if (a.target === b.target) value = true;
+                        else if (command.type === 'addExclusive') value = false;
+                    }
+                }
+            }
+        }
+    }
+    return value;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): any {
+    if (!hasDeferredTrait(world, entity, trait)) return undefined;
+    let value = isEntityAlive(world[$internal].entityIndex, entity) ? getTrait(world, entity, trait) : undefined;
+    for (const command of commands(world)) {
+        if (command.entity !== entity || (command.type !== 'spawn' && command.type !== 'add' && command.type !== 'addExclusive')) continue;
+        for (const config of command.traits) {
+            const item = Array.isArray(config) ? config[0] : config;
+            const params = Array.isArray(config) ? config[1] : isRelationPair(item) ? item[$internal].params : undefined;
+            if (item === trait) value = params;
+            if (isRelationPair(item) && isRelationPair(trait)) {
+                const a = item[$internal], b = trait[$internal];
+                if (a.relation === b.relation && a.target === b.target) value = params;
+            }
+        }
+    }
+    return value;
+}
+
+export function beginDeferredScope(world: World): DeferredScope {
+    const scope = { commands: [] };
+    world[$internal].deferredScopes.push(scope);
+    return scope;
+}
+
+export function endDeferredScope(world: World, scope: DeferredScope) {
+    flushScope(world, scope);
+    const scopes = world[$internal].deferredScopes;
+    scopes.splice(scopes.lastIndexOf(scope), 1);
+}
+
+function applyAdd(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    for (const config of traits) {
+        addTrait(world, entity, config);
+        const trait = Array.isArray(config) ? config[0] : config;
+        const value = Array.isArray(config) ? config[1] : isRelationPair(trait) ? trait[$internal].params : undefined;
+        // addTrait intentionally does not overwrite an existing value; deferred adds do.
+        if (value !== undefined && hasTrait(world, entity, isRelationPair(trait) ? trait[$internal].relation[$internal].trait : trait)) {
+            setTrait(world, entity, trait as Trait | RelationPair, value, true);
+        }
+    }
+}
+
+function flushScope(world: World, scope: DeferredScope) {
+    if (!scope.commands.length) return;
+    const pending = scope.commands.splice(0);
+    const ctx = world[$internal];
+    const spawned = new Set<Entity>();
+    for (const command of pending) if (command.type === 'spawn') spawned.add(command.entity);
+    const nullified = new Set<Entity>();
+    for (const command of pending) if (command.type === 'destroy' && spawned.has(command.entity)) nullified.add(command.entity);
+
+    for (const command of pending) {
+        const entity = command.entity;
+        if (nullified.has(entity)) continue;
+        if (command.type === 'spawn') {
+            // The id was reserved when queued, so initialize it in place.
+            ctx.entityTraits.set(entity, new Set());
+            applyAdd(world, entity, command.traits);
+            continue;
+        }
+        if (!isEntityAlive(ctx.entityIndex, entity)) continue;
+        if (command.type === 'destroy') {
+            if (entity === ctx.worldEntity) throw new Error('Koota: The world entity cannot be destroyed by a deferred command.');
+            destroyEntity(world, entity);
+        } else if (command.type === 'add') applyAdd(world, entity, command.traits);
+        else if (command.type === 'remove') removeTrait(world, entity, ...command.traits);
+        else {
+            for (const item of command.traits) {
+                const pair = Array.isArray(item) ? item[0] : item;
+                if (!isRelationPair(pair)) {
+                    applyAdd(world, entity, [item]);
+                    continue;
+                }
+                removeTrait(world, entity, pair[$internal].relation('*'));
+                if (pair[$internal].target !== '*') applyAdd(world, entity, [item]);
+            }
+        }
+    }
+    // Cancelled spawns must release their reserved IDs without ever becoming entities.
+    for (const entity of nullified) releaseEntity(ctx.entityIndex, entity);
+}
+
+export function flushDeferred(world: World) {
+    const scope = world[$internal].deferredScopes.at(-1);
+    if (scope) flushScope(world, scope);
+}
+
+export function flushDeferredEntity(world: World, entity: Entity) {
+    for (const scope of [...world[$internal].deferredScopes]) {
+        if (scope.commands.some((command) => command.entity === entity)) flushScope(world, scope);
+    }
+}
+
+export function createDeferredWorld(world: World): DeferredWorld {
+    const current = () => world[$internal].deferredScopes.at(-1) ?? beginDeferredScope(world);
+    return {
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            current().commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current().commands.push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current().commands.push({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { current().commands.push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, ...traits) { current().commands.push({ type: 'addExclusive', entity, traits }); },
+        flush() { flushDeferred(world); },
+    };
+}
